import React, { useState } from 'react';
import { Send, Brain, Sparkles, Calculator, Users, Loader } from 'lucide-react';

const ModeratedBrain = () => {
  const [userInput, setUserInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [error, setError] = useState(null);
  const [processingSteps, setProcessingSteps] = useState([]);

  // System prompts
  const MODERATOR_PROMPT = `You are the Moderator - a meta-cognitive orchestrator managing a conversation between two thinking systems:

**System 1 (Creative):** Intuitive, expansive, imaginative, exploratory
**System 2 (Analytical):** Rigorous, critical, structured, feasibility-focused

Your role:
- Parse the user's prompt and identify key discussion topics
- Decide who speaks next and guide the conversation
- Set appropriate response lengths (brief, moderate, or extended)
- Ask follow-up questions to deepen thinking
- Know when to let a system flow and when to enforce discipline
- Guide toward synthesis and conclusion
- Recognize when the conversation is complete

Response format (JSON):
{
  "nextSpeaker": "System1" | "System2" | "Done",
  "instruction": "Brief instruction for the speaker",
  "tokenLimit": 100-600,
  "reasoning": "Why this decision"
}

Examples:
- "System 1, paint the core vision" (tokenLimit: 500)
- "System 2, keep it tight - top 3 concerns only" (tokenLimit: 150)
- "System 1, how does that make you feel?" (tokenLimit: 100)
- "System 2, stress-test that idea" (tokenLimit: 300)

You are the shepherd of the prompt.`;

  const SYSTEM_1_PROMPT = `You are System 1 - the creative, intuitive, divergent thinking system.

Your role:
- Generate wild ideas, explore possibilities
- Be expansive and imaginative
- Follow intuition and associations
- Embrace ambiguity and metaphor
- Think fast, think broadly

You are in a MODERATED conversation:
- The Moderator will give you specific instructions
- Follow their guidance on length and focus
- Respond to System 2's points when prompted
- Be concise when asked, expansive when allowed

Style: Conversational, energetic, exploratory`;

  const SYSTEM_2_PROMPT = `You are System 2 - the analytical, logical, convergent thinking system.

Your role:
- Provide structured, precise analysis
- Validate ideas critically
- Identify problems and edge cases
- Be methodical and thorough
- Focus on feasibility and logic

You are in a MODERATED conversation:
- The Moderator will give you specific instructions
- Follow their guidance on length and focus
- Respond to System 1's ideas when prompted
- Be concise when asked, detailed when allowed

Style: Professional, clear, rigorous`;

  const callLLM = async (systemPrompt, userMessage, maxTokens) => {
    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        model: "claude-sonnet-4-20250514",
        max_tokens: maxTokens,
        messages: [
          {
            role: "user",
            content: `${systemPrompt}\n\n${userMessage}`
          }
        ]
      })
    });

    if (!response.ok) {
      throw new Error(`API call failed: ${response.status}`);
    }

    const data = await response.json();
    return data.content[0].text;
  };

  const callModerator = async (prompt, conversationHistory) => {
    const contextSummary = conversationHistory.length > 0
      ? `\n\nConversation so far:\n${conversationHistory.map(h => `${h.speaker}: ${h.output.substring(0, 200)}...`).join('\n')}`
      : '';

    const message = `Original prompt: "${prompt}"${contextSummary}

Based on the prompt and conversation state, decide what happens next.
Return ONLY valid JSON with no additional text.`;

    const response = await callLLM(MODERATOR_PROMPT, message, 300);

    // Parse moderator decision (strip markdown if present)
    let cleaned = response.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    return JSON.parse(cleaned);
  };

  const handleSubmit = async () => {
    if (!userInput.trim()) return;

    setLoading(true);
    setError(null);
    setResults(null);
    setProcessingSteps([]);

    try {
      const conversationHistory = [];
      let turn = 0;
      const MAX_TURNS = 10; // Safety limit

      setProcessingSteps(prev => [...prev, {
        step: 'Moderator initializing',
        message: 'Analyzing prompt and planning conversation...',
        type: 'moderator'
      }]);

      while (turn < MAX_TURNS) {
        // Moderator decides next move
        const decision = await callModerator(userInput, conversationHistory);

        if (decision.nextSpeaker === 'Done') {
          setProcessingSteps(prev => [...prev, {
            step: 'Moderator concludes',
            message: decision.reasoning || 'Conversation complete',
            type: 'moderator'
          }]);
          break;
        }

        // Log moderator decision
        setProcessingSteps(prev => [...prev, {
          step: `Moderator → ${decision.nextSpeaker}`,
          message: decision.instruction,
          reasoning: decision.reasoning,
          tokenLimit: decision.tokenLimit,
          type: 'moderator',
          processing: true
        }]);

        // Select system and get response
        const systemPrompt = decision.nextSpeaker === 'System1' ? SYSTEM_1_PROMPT : SYSTEM_2_PROMPT;
        const systemLabel = decision.nextSpeaker === 'System1' ? 'System 1 (Creative)' : 'System 2 (Analytical)';

        const contextPrefix = conversationHistory.length > 0
          ? `Previous conversation:\n${conversationHistory.map(h => `${h.speaker}: ${h.output}`).join('\n\n')}\n\nModerator instruction: ${decision.instruction}\n\n`
          : `Moderator instruction: ${decision.instruction}\n\n`;

        const systemResponse = await callLLM(
          systemPrompt,
          `${contextPrefix}Respond to: "${userInput}"`,
          decision.tokenLimit || 400
        );

        conversationHistory.push({
          speaker: systemLabel,
          system: decision.nextSpeaker,
          instruction: decision.instruction,
          output: systemResponse,
          tokenLimit: decision.tokenLimit
        });

        setProcessingSteps(prev => {
          const newSteps = [...prev];
          newSteps[newSteps.length - 1].processing = false;
          newSteps[newSteps.length - 1].output = systemResponse;
          return newSteps;
        });

        turn++;
      }

      // Assemble final output
      const finalOutput = conversationHistory.map(h => h.output).join('\n\n---\n\n');

      setResults({
        conversationHistory,
        finalOutput,
        totalTurns: turn,
        timestamp: new Date().toLocaleTimeString()
      });

    } catch (err) {
      console.error('Error:', err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const examplePrompts = [
    "Design a revolutionary AI-powered personal assistant",
    "Explain the future of remote work in 2030",
    "Create a business model for sustainable fashion",
    "What's the best approach to learning quantum computing?"
  ];

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0f0f1e 0%, #1a1a2e 100%)',
      color: '#e0e0e0',
      padding: '40px 20px',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif'
    }}>
      <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '40px' }}>
          <div style={{ fontSize: '48px', marginBottom: '10px' }}>🧠⚡👨‍⚖️</div>
          <h1 style={{ 
            color: '#ff6b6b', 
            fontSize: '2.5em', 
            margin: '0 0 10px 0' 
          }}>
            Moderated Dual-Process System
          </h1>
          <p style={{ color: '#a0a0a0', fontSize: '1.2em' }}>
            Three-system architecture: Moderator orchestrates Creative ↔ Analytical
          </p>
        </div>

        {/* System Overview */}
        <div style={{
          background: 'rgba(167, 139, 250, 0.1)',
          border: '2px solid rgba(167, 139, 250, 0.3)',
          borderRadius: '15px',
          padding: '25px',
          marginBottom: '30px'
        }}>
          <h3 style={{ color: '#a78bfa', marginTop: 0 }}>🎭 The Three Systems</h3>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '15px' }}>
            <div style={{ padding: '15px', background: 'rgba(255, 154, 118, 0.1)', borderRadius: '10px' }}>
              <div style={{ fontSize: '24px', marginBottom: '5px' }}>🎨</div>
              <strong style={{ color: '#ff9a76' }}>System 1: Creative</strong>
              <div style={{ fontSize: '13px', color: '#a0a0a0', marginTop: '5px' }}>
                Intuitive, expansive, exploratory
              </div>
            </div>
            <div style={{ padding: '15px', background: 'rgba(108, 155, 209, 0.1)', borderRadius: '10px' }}>
              <div style={{ fontSize: '24px', marginBottom: '5px' }}>🔧</div>
              <strong style={{ color: '#6c9bd1' }}>System 2: Analytical</strong>
              <div style={{ fontSize: '13px', color: '#a0a0a0', marginTop: '5px' }}>
                Rigorous, critical, structured
              </div>
            </div>
            <div style={{ padding: '15px', background: 'rgba(167, 139, 250, 0.1)', borderRadius: '10px' }}>
              <div style={{ fontSize: '24px', marginBottom: '5px' }}>👨‍⚖️</div>
              <strong style={{ color: '#a78bfa' }}>Moderator: Orchestrator</strong>
              <div style={{ fontSize: '13px', color: '#a0a0a0', marginTop: '5px' }}>
                Guides conversation, manages turns
              </div>
            </div>
          </div>
        </div>

        {/* Input Section */}
        <div style={{
          background: 'rgba(255, 255, 255, 0.05)',
          border: '2px solid rgba(255, 255, 255, 0.1)',
          borderRadius: '15px',
          padding: '25px',
          marginBottom: '30px'
        }}>
          <label style={{ 
            display: 'block', 
            marginBottom: '10px', 
            color: '#ffd93d',
            fontWeight: 'bold'
          }}>
            Enter your prompt:
          </label>

          <textarea
            value={userInput}
            onChange={(e) => setUserInput(e.target.value)}
            placeholder="The Moderator will orchestrate a conversation between creative and analytical thinking..."
            style={{
              width: '100%',
              minHeight: '100px',
              padding: '15px',
              background: 'rgba(255, 255, 255, 0.05)',
              border: '1px solid rgba(255, 255, 255, 0.2)',
              borderRadius: '10px',
              color: '#e0e0e0',
              fontSize: '16px',
              fontFamily: 'inherit',
              resize: 'vertical',
              marginBottom: '15px'
            }}
          />

          <div style={{ 
            display: 'flex', 
            gap: '10px', 
            flexWrap: 'wrap',
            marginBottom: '15px'
          }}>
            {examplePrompts.map((prompt, i) => (
              <button
                key={i}
                onClick={() => setUserInput(prompt)}
                style={{
                  padding: '8px 15px',
                  background: 'rgba(167, 139, 250, 0.2)',
                  border: '1px solid rgba(167, 139, 250, 0.4)',
                  borderRadius: '8px',
                  color: '#a78bfa',
                  fontSize: '14px',
                  cursor: 'pointer'
                }}
              >
                {prompt}
              </button>
            ))}
          </div>

          <button
            onClick={handleSubmit}
            disabled={loading || !userInput.trim()}
            style={{
              padding: '12px 30px',
              background: loading ? '#555' : 'linear-gradient(135deg, #a78bfa 0%, #ff9a76 100%)',
              border: 'none',
              borderRadius: '10px',
              color: 'white',
              fontSize: '16px',
              fontWeight: 'bold',
              cursor: loading ? 'not-allowed' : 'pointer',
              display: 'flex',
              alignItems: 'center',
              gap: '10px',
              opacity: loading || !userInput.trim() ? 0.5 : 1
            }}
          >
            {loading ? (
              <>
                <Loader className="spin" size={20} />
                Moderator orchestrating...
              </>
            ) : (
              <>
                <Send size={20} />
                Start Moderated Conversation
              </>
            )}
          </button>
        </div>

        {/* Error Display */}
        {error && (
          <div style={{
            background: 'rgba(255, 107, 107, 0.1)',
            border: '2px solid rgba(255, 107, 107, 0.3)',
            borderRadius: '15px',
            padding: '20px',
            marginBottom: '30px',
            color: '#ff6b6b'
          }}>
            <strong>Error:</strong> {error}
          </div>
        )}

        {/* Processing Steps */}
        {processingSteps.length > 0 && (
          <div style={{
            background: 'rgba(167, 139, 250, 0.1)',
            border: '2px solid rgba(167, 139, 250, 0.3)',
            borderRadius: '15px',
            padding: '25px',
            marginBottom: '30px'
          }}>
            <h3 style={{ color: '#a78bfa', marginTop: 0 }}>
              🎭 Moderated Conversation Flow
            </h3>
            {processingSteps.map((step, i) => (
              <div key={i} style={{
                marginBottom: '15px',
                paddingBottom: '15px',
                borderBottom: i < processingSteps.length - 1 ? '1px solid rgba(255,255,255,0.1)' : 'none'
              }}>
                <div style={{ 
                  display: 'flex', 
                  alignItems: 'center',
                  gap: '10px',
                  marginBottom: '8px'
                }}>
                  {step.processing && <Loader className="spin" size={16} />}
                  {step.type === 'moderator' ? (
                    <Users size={16} color="#a78bfa" />
                  ) : (
                    step.system === 'System1' ? <Sparkles size={16} color="#ff9a76" /> : <Calculator size={16} color="#6c9bd1" />
                  )}
                  <strong style={{ 
                    color: step.type === 'moderator' ? '#a78bfa' : '#ffd93d' 
                  }}>
                    {step.step}
                  </strong>
                  {step.tokenLimit && (
                    <span style={{
                      padding: '2px 6px',
                      background: 'rgba(255, 217, 61, 0.2)',
                      borderRadius: '4px',
                      fontSize: '11px',
                      color: '#ffd93d'
                    }}>
                      {step.tokenLimit} tokens
                    </span>
                  )}
                </div>
                {step.message && (
                  <div style={{ 
                    color: step.type === 'moderator' ? '#a78bfa' : '#e0e0e0',
                    fontSize: '14px',
                    fontStyle: 'italic',
                    marginLeft: '26px'
                  }}>
                    "{step.message}"
                  </div>
                )}
                {step.reasoning && (
                  <div style={{ 
                    color: '#888',
                    fontSize: '12px',
                    marginLeft: '26px',
                    marginTop: '4px'
                  }}>
                    Why: {step.reasoning}
                  </div>
                )}
                {step.output && (
                  <div style={{
                    background: 'rgba(0,0,0,0.3)',
                    padding: '12px',
                    borderRadius: '6px',
                    fontSize: '13px',
                    marginTop: '8px',
                    marginLeft: '26px',
                    lineHeight: '1.6'
                  }}>
                    {step.output}
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        {/* Final Results */}
        {results && (
          <div style={{ display: 'grid', gap: '20px' }}>
            {/* Metrics */}
            <div style={{
              background: 'rgba(78, 205, 196, 0.1)',
              border: '2px solid rgba(78, 205, 196, 0.3)',
              borderRadius: '15px',
              padding: '20px'
            }}>
              <h3 style={{ color: '#4ecdc4', marginTop: 0 }}>📊 Conversation Metrics</h3>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px' }}>
                <div>
                  <div style={{ fontSize: '12px', color: '#a0a0a0' }}>Total Turns</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold' }}>
                    {results.totalTurns}
                  </div>
                </div>
                <div>
                  <div style={{ fontSize: '12px', color: '#a0a0a0' }}>Systems Engaged</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#4ecdc4' }}>
                    3 (Mod + S1 + S2)
                  </div>
                </div>
              </div>
            </div>

            {/* Final Output */}
            <div style={{
              background: 'rgba(255, 217, 61, 0.1)',
              border: '2px solid rgba(255, 217, 61, 0.3)',
              borderRadius: '15px',
              padding: '25px'
            }}>
              <h3 style={{ color: '#ffd93d', marginTop: 0 }}>
                🎯 Complete Conversation
              </h3>
              <div style={{
                background: 'rgba(0, 0, 0, 0.2)',
                padding: '20px',
                borderRadius: '10px',
                lineHeight: '1.8',
                whiteSpace: 'pre-wrap'
              }}>
                {results.finalOutput}
              </div>
            </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
        .spin {
          animation: spin 1s linear infinite;
        }
      `}</style>
    </div>
  );
};

export default ModeratedBrain;
